	@Test
	void forgedScalarSubqueryCannotBorrowCapturedRootProvenance() {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		StatementPattern left = pattern("urn:test:left");
		Join right = new Join(pattern("urn:test:right-a"), pattern("urn:test:right-b"));
		Difference root = new Difference(left, right);
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);

		RuleSpec spec = RuleDsl.rule("test-forged-scalar-subquery-provenance")
				.kind(RuleKind.TRANSFORMATION)
				.match(RuleDsl.difference("root", RuleDsl.capture("left"), RuleDsl.capture("right")))
				.emit((capture, builder) -> {
					var difference = capture.node("root");
					var rightRootId = difference.inputs().get(1);
					var changedDescendantId = capture.ir().node(rightRootId).inputs().get(1);
					PlanIr replacement = TupleExprToIr.convert(pattern("urn:test:forged"), null,
							capture.ir().universe());
					List<IrNode> forgedNodes = new ArrayList<>(capture.ir().nodes());
					forgedNodes.set(changedDescendantId.value(), replacement.rootNode().withId(changedDescendantId));
					PlanIr forgedSubquery = new PlanIr(capture.ir().universe(), rightRootId, forgedNodes);
					var copiedLeft = builder.copySubtreeFrom(capture.ir(), difference.inputs().get(0));
					return builder.filter(copiedLeft, new ScalarExpr.Exists(forgedSubquery, BindingMask.EMPTY, true));
				})
				.proof("authoritativeScalarProvenance")
				.reason("Test-only forged scalar subquery")
				.build();
		CompiledRule rule = RuleCompiler.compile(spec);

		List<RuleApplication> applications = rule.apply(rootExpression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertEquals(0, applications.size(),
				"A scalar PlanIr with only a captured root node must not borrow that root's memo group: "
						+ applications);
	}

	@Test
	void wildcardCopiedDescendantUsesItsTypedRecipeWithoutChoosingAGroupAlternative() {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		Join capturedJoin = new Join(pattern("urn:test:retained"), pattern("urn:test:other"));
		Difference root = new Difference(capturedJoin, pattern("urn:test:right"));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		int capturedJoinGroupId = rootExpression.inputGroupIds().get(0);
		MemoExpr capturedJoinExpression = memo.group(capturedJoinGroupId).expressionAt(0);
		int retainedGroupId = capturedJoinExpression.inputGroupIds().get(0);
		int otherGroupId = capturedJoinExpression.inputGroupIds().get(1);
		int rightGroupId = rootExpression.inputGroupIds().get(1);
		memo.addLogicalAlternativeWithInputs(capturedJoinGroupId,
				new Join(capturedJoin.getRightArg().clone(), capturedJoin.getLeftArg().clone()),
				List.of(otherGroupId, retainedGroupId), List.of()).orElseThrow();

		RuleSpec spec = RuleDsl.rule("test-wildcard-copied-descendant-recipe")
				.kind(RuleKind.TRANSFORMATION)
				.match(RuleDsl.difference("root", RuleDsl.capture("left"), RuleDsl.capture("right")))
				.emit((capture, builder) -> {
					IrNode capturedLeft = capture.node("left");
					var retained = builder.copySubtreeFrom(capture.ir(), capturedLeft.inputs().getFirst());
					var right = builder.copySubtreeFrom(capture.ir(), capture.nodeId("right"));
					return builder.difference(retained, right);
				})
				.proof("typedCaptureLocalRecipe")
				.reason("Test-only wildcard descendant reconstruction")
				.build();
		CompiledRule rule = RuleCompiler.compile(spec);

		List<RuleApplication> applications = rule.apply(rootExpression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertEquals(1, applications.size(),
				"A copied wildcard descendant must be reconstructed from its typed recipe");
		RuleApplication application = applications.getFirst();
		MemoExpr added = memo.addLogicalAlternativeWithInputRecipes(application.targetGroupId(),
				application.alternative(), application.logicalInputRecipes(), application.proofs(), SemanticScope.BAG,
				application.inputRequirements(), application.inputSemanticRequirements()).orElseThrow();
		assertEquals(List.of(retainedGroupId, rightGroupId), added.inputGroupIds(),
				"Structural reconstruction must resolve the copied route, not choose another capture-group alternative");
	}

	@Test
	void capturedObserverRouteRebuildRetainsAuthoritativeScalarGroup() {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		StatementPattern retained = pattern("urn:test:retained");
		StatementPattern optional = new StatementPattern(new Var("s"),
				new Var("optionalPredicate", VF.createIRI("urn:test:optional")), new Var("unused"));
		StatementPattern exists = new StatementPattern(new Var("s"),
				new Var("existsPredicate", VF.createIRI("urn:test:exists")), new Var("probe"));
		Filter filter = new Filter(new LeftJoin(retained, optional), new Exists(exists));
		Group root = new Group(filter);
		root.addGroupElement(new GroupElem("count", new Count(new Var("o"), true)));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		MemoExpr filterExpression = memo.group(rootExpression.inputs().getFirst().groupId()).expressionAt(0);
		int authoritativeScalarGroupId = filterExpression.inputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.SCALAR_SUBQUERY)
				.mapToInt(MemoInput::groupId)
				.findFirst()
				.orElseThrow();
		MemoExpr leftJoinExpression = memo.group(filterExpression.inputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.ARGUMENT)
				.findFirst()
				.orElseThrow()
				.groupId()).expressionAt(0);
		int retainedGroupId = leftJoinExpression.inputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.LEFT)
				.mapToInt(MemoInput::groupId)
				.findFirst()
				.orElseThrow();

		RuleSpec spec = RuleDsl.rule("test-captured-observer-route-scalar-provenance")
				.kind(RuleKind.TRANSFORMATION)
				.match(RulePattern.op("root", IrOp.GROUP, List.of(RuleDsl.captureRoute("input"))))
				.emit((capture, builder) -> {
					IrNode filterNode = capture.node("input");
					IrNode leftJoinNode = capture.ir().node(filterNode.inputs().getFirst());
					var retainedInput = builder.copySubtreeFrom(capture.ir(), leftJoinNode.inputs().getFirst());
					var condition = ((IrAttr.Condition) filterNode.attr()).expression();
					var rewrittenFilter = builder.filter(retainedInput, condition);
					return builder.unary(IrOp.GROUP, rewrittenFilter, capture.node("root").attr());
				})
				.proofSemanticScope(SemanticScope.SET)
				.proof("authoritativeDeepRoute", "authoritativeScalarProvenance")
				.reason("Test-only observer route reconstruction")
				.build();
		CompiledRule rule = RuleCompiler.compile(spec);

		List<RuleApplication> applications = rule.apply(rootExpression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertEquals(1, applications.size(),
				"A captured observer route must preserve authoritative descendant scalar provenance");
		RuleApplication application = applications.getFirst();
		assertTrue(application.logicalInputRecipes().getFirst() instanceof LogicalInputRecipe.NewGroup);
		LogicalInputRecipe.NewGroup filterRecipe = (LogicalInputRecipe.NewGroup) application.logicalInputRecipes()
				.getFirst();
		assertEquals(List.of(new LogicalInputRecipe.ExistingGroup(retainedGroupId),
				new LogicalInputRecipe.ExistingGroup(authoritativeScalarGroupId)), filterRecipe.inputs());
		MemoExpr added = memo.addLogicalAlternativeWithInputRecipes(application.targetGroupId(),
				application.alternative(), application.logicalInputRecipes(), application.proofs(), SemanticScope.SET,
				application.inputRequirements(), application.inputSemanticRequirements()).orElseThrow();
		MemoExpr rewrittenFilter = memo.group(added.inputs().getFirst().groupId())
				.expressions()
				.stream()
				.filter(expression -> expression.tupleExpr() instanceof Filter)
				.findFirst()
				.orElseThrow();
		MemoInput scalarInput = rewrittenFilter.inputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.SCALAR_SUBQUERY)
				.findFirst()
				.orElseThrow();
		assertAll(
				() -> assertEquals(authoritativeScalarGroupId, scalarInput.groupId()),
				() -> assertEquals(SemanticScope.EXISTENCE, scalarInput.requiredSemanticScope()),
				() -> assertTrue(scalarInput.semanticBarrier()));
	}

	@Test
	void coalescedHelperCycleRejectsTransactionWithoutOrphans() {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		StatementPattern left = pattern("urn:test:left");
		StatementPattern right = pattern("urn:test:right");
		Difference root = new Difference(left, right);
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		int leftGroupId = rootExpression.inputGroupIds().get(0);

		RuleSpec spec = RuleDsl.rule("test-coalesced-helper-cycle")
				.kind(RuleKind.TRANSFORMATION)
				.match(RuleDsl.difference("root", RuleDsl.capture("left"), RuleDsl.capture("right")))
				.emit(RuleDsl.difference(
						RuleDsl.join(RuleDsl.ref("left"), RuleDsl.ref("right")),
						RuleDsl.project(RuleDsl.ref("left"), RuleDsl.shape("left").possible())))
				.proof("transactionalMemoRecipe")
				.reason("Test-only helper coalescence cycle")
				.build();
		CompiledRule rule = RuleCompiler.compile(spec);
		var capture = rule.trace(rootExpression, OptimizationGoal.root()).capture().orElseThrow();
		PlanIrBuilder builder = new PlanIrBuilder(capture.ir().universe());
		Difference emitted = (Difference) IrToTupleExpr.convert(
				builder.build(spec.template().emit(capture, builder)));
		Projection projectionOfLeft = (Projection) emitted.getRightArg();
		int coalescedGroupId = memo.intern(projectionOfLeft, List.of(leftGroupId));
		Projection projectionOfTarget = projectionOfLeft.clone();
		projectionOfTarget.setArg(root.clone());
		assertTrue(memo.addLogicalAlternativeWithInputs(coalescedGroupId, projectionOfTarget,
				List.of(rootGroupId), List.of()).isPresent());
		int groupsBeforeRejectedRewrite = memo.groups().size();

		List<RuleApplication> applications = rule.apply(rootExpression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertAll(
				() -> assertEquals(0, applications.size(),
						"A compiled rewrite must fail closed before publishing a cyclic helper recipe: "
								+ applications),
				() -> assertEquals(groupsBeforeRejectedRewrite, memo.groups().size(),
						"Rejecting a coalesced helper cycle must not strand an eagerly interned helper group"));
	}

	@Test
	void laterHelperPreparationFailurePublishesNothing() {
		CascadesCostModel delegate = CascadesCostModel.from(new EvaluationStatistics());
		CascadesCostModel failingCostModel = new CascadesCostModel() {
			private int projectionPropertiesCalls;

			@Override
			public LogicalProperties logicalProperties(TupleExpr tupleExpr) {
				if (tupleExpr instanceof Projection && ++projectionPropertiesCalls == 2) {
					throw new IllegalStateException("second helper property failure");
				}
				return delegate.logicalProperties(tupleExpr);
			}

			@Override
			public String logicalFingerprint(TupleExpr tupleExpr) {
				return delegate.logicalFingerprint(tupleExpr);
			}

			@Override
			public CostVector localCost(MemoExpr expression, OptimizationGoal goal, List<Winner> inputWinners) {
				return delegate.localCost(expression, goal, inputWinners);
			}

			@Override
			public PhysicalProperties deliveredProperties(MemoExpr expression, OptimizationGoal goal,
					List<Winner> inputWinners) {
				return delegate.deliveredProperties(expression, goal, inputWinners);
			}
		};
		Memo memo = new Memo(failingCostModel);
		Difference root = new Difference(pattern("urn:test:left"), pattern("urn:test:right"));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		ProjectionElemList projectedBindings = new ProjectionElemList(
				new ProjectionElem("s"), new ProjectionElem("p"), new ProjectionElem("o"));
		Projection leftHelper = new Projection(root.getLeftArg().clone(), projectedBindings.clone(), false);
		Projection rightHelper = new Projection(root.getRightArg().clone(), projectedBindings.clone(), false);
		Difference alternative = new Difference(leftHelper, rightHelper);
		List<LogicalInputRecipe> recipes = List.of(
				new LogicalInputRecipe.NewGroup(leftHelper,
						List.of(new LogicalInputRecipe.ExistingGroup(rootExpression.inputGroupIds().get(0)))),
				new LogicalInputRecipe.NewGroup(rightHelper,
						List.of(new LogicalInputRecipe.ExistingGroup(rootExpression.inputGroupIds().get(1)))));
		int groupsBefore = memo.groups().size();
		int expressionsBefore = memo.groups().stream().mapToInt(MemoGroup::expressionCount).sum();

		assertThrows(IllegalStateException.class,
				() -> memo.addLogicalAlternativeWithInputRecipes(rootGroupId, alternative, recipes, List.of(),
						SemanticScope.BAG, List.of(), MemoInputLayout.semanticRequirements(alternative)));

		assertAll(
				() -> assertEquals(groupsBefore, memo.groups().size(),
						"A later helper failure must not publish an earlier helper group"),
				() -> assertEquals(expressionsBefore,
						memo.groups().stream().mapToInt(MemoGroup::expressionCount).sum(),
						"A later helper failure must not publish any helper expression"));
	}

	@Test
	void freshHelperTypedAliasResolvesToAuthoritativeGroup() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Difference root = new Difference(pattern("urn:test:left"), pattern("urn:test:right"));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		int leftGroupId = rootExpression.inputGroupIds().get(0);
		int rightGroupId = rootExpression.inputGroupIds().get(1);
		Projection helper = identityProjection(root.getLeftArg().clone());
		int canonicalHelperGroupId = memo.intern(helper, List.of(leftGroupId));
		Filter aliasOwner = new Filter(root.getLeftArg().clone(), new Bound(new Var("s")));
		int aliasGroupId = memo.intern(aliasOwner, List.of(leftGroupId));
		assertTrue(memo.addLogicalAlternativeWithInputs(aliasGroupId, helper.clone(), List.of(leftGroupId), List.of())
				.isPresent());
		assertTrue(canonicalHelperGroupId != aliasGroupId);
		Difference alternative = new Difference(helper.clone(), root.getRightArg().clone());
		List<LogicalInputRecipe> recipes = List.of(
				new LogicalInputRecipe.NewGroup(helper.clone(),
						List.of(new LogicalInputRecipe.ExistingGroup(leftGroupId))),
				new LogicalInputRecipe.ExistingGroup(rightGroupId));
		Memo.LogicalInputValidation validation = memo.validateLogicalInputRecipes(rootGroupId, alternative, recipes);
		MemoExpr added = memo.addLogicalAlternativeWithInputRecipes(rootGroupId, alternative, recipes,
				List.of(), SemanticScope.BAG, List.of(), MemoInputLayout.semanticRequirements(alternative))
				.orElseThrow();

		assertAll(
				() -> assertTrue(validation.supported(), validation::failureReason),
				() -> assertEquals(canonicalHelperGroupId, added.inputGroupIds().getFirst(),
						"A fresh helper must reuse its authoritative typed-identity group"));
	}

	@Test
	void capturedAliasGroupRemainsExact() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Difference root = new Difference(pattern("urn:test:left"), pattern("urn:test:right"));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressionAt(0);
		int leftGroupId = rootExpression.inputGroupIds().get(0);
		int rightGroupId = rootExpression.inputGroupIds().get(1);
		Projection helper = identityProjection(root.getLeftArg().clone());
		int canonicalHelperGroupId = memo.intern(helper, List.of(leftGroupId));
		Filter aliasOwner = new Filter(root.getLeftArg().clone(), new Bound(new Var("s")));
		int aliasGroupId = memo.intern(aliasOwner, List.of(leftGroupId));
		assertTrue(memo.addLogicalAlternativeWithInputs(aliasGroupId, helper.clone(), List.of(leftGroupId), List.of())
				.isPresent());
		assertTrue(canonicalHelperGroupId != aliasGroupId);
		Difference alternative = new Difference(helper.clone(), root.getRightArg().clone());

		MemoExpr added = memo.addLogicalAlternativeWithInputRecipes(rootGroupId, alternative,
				List.of(new LogicalInputRecipe.ExistingGroup(aliasGroupId),
						new LogicalInputRecipe.ExistingGroup(rightGroupId)),
				List.of(), SemanticScope.BAG, List.of(), MemoInputLayout.semanticRequirements(alternative))
				.orElseThrow();

		assertEquals(aliasGroupId, added.inputGroupIds().getFirst(),
				"An exact captured alias must not be silently redirected to the canonical typed-key group");
	}

	private static Projection identityProjection(TupleExpr input) {
		return new Projection(input, new ProjectionElemList(
				new ProjectionElem("s"), new ProjectionElem("p"), new ProjectionElem("o")), false);
	}

	private static StatementPattern pattern(String predicate) {
		return new StatementPattern(new Var("s"), new Var("p", VF.createIRI(predicate)), new Var("o"));
	}

